-- Enrichment marathon batch: ScyllaDB, SE Ranking, Seafile, Seamless.AI, SeaTable, Seatsurfing, SeaweedFS, Security Onion

-- ── ScyllaDB ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$High-performance, low-latency NoSQL database compatible with Apache Cassandra and Amazon DynamoDB APIs, built in C++ for predictable performance at scale.$q$, short_description),
  pricing_model = COALESCE($q$Open source core with paid Enterprise (self-managed) and fully managed Cloud tiers$q$, pricing_model),
  starting_price = COALESCE($q$Free (open source); ScyllaDB Cloud and Enterprise pricing available on request$q$, starting_price),
  founded_year = COALESCE(2015, founded_year),
  company_size = COALESCE($q$Approximately 150 to 230 employees$q$, company_size),
  headquarters = COALESCE($q$Palo Alto, California, USA, with a major research and development office in Tel Aviv, Israel$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$ScyllaDB Review 2026: Pricing, Features and NoSQL Database Guide$q$, seo_title),
  seo_meta_description = COALESCE($q$ScyllaDB is a Cassandra and DynamoDB compatible NoSQL database built in C++. See 2026 pricing, features, pros, cons and how it compares for high throughput apps.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$ScyllaDB is a high-performance, distributed NoSQL database originally developed by Cloudius Systems, a company founded by former Red Hat and KVM engineers Avi Kivity and Dor Laor, which was renamed ScyllaDB and open sourced its core database around 2015. Written in C++ using the Seastar shard-per-core framework, ScyllaDB is designed as a drop-in, wire-compatible replacement for Apache Cassandra and offers a native DynamoDB-compatible API called Alternator, letting teams run DynamoDB style workloads outside of AWS without rewriting application code. The company is headquartered in Palo Alto, California, with a significant engineering presence in Tel Aviv, Israel, and a distributed team reported to work across roughly two dozen countries; employee counts from third party sources range from about 150 to 230 people. ScyllaDB is offered in three ways: a free, community-supported Open Source edition available on GitHub under the AGPL license; a self-managed Enterprise edition for on-premises or private cloud deployments that adds premium features such as workload prioritization, encryption at rest, and dedicated support with custom pricing; and ScyllaDB Cloud (marketed as ScyllaDB X Cloud), a fully managed database-as-a-service running on AWS and Google Cloud Platform with Standard, Professional, and Premium support tiers offering response times ranging from two hours down to fifteen minutes for the most critical issues. None of the paid tiers publish flat list prices; ScyllaDB Cloud billing is based on provisioned cluster resources such as instance type, storage, and service plan, and prospective customers use an online calculator or contact sales for a quote. The database is aimed at data-intensive applications that need high throughput and predictable low-latency performance, and publicly named users and case studies include Discord, Disney+, Expedia, Zillow, Palo Alto Networks, and Tripadvisor. Because it retains close wire compatibility with Cassandra's CQL and Cassandra Query Language drivers, plus optional DynamoDB API compatibility, ScyllaDB is commonly evaluated by engineering teams that are hitting latency, cost, or operational scaling limits with either of those two systems and want a lower-latency alternative without a full data model rewrite. For an SEO directory or comparison context, the key verifiable facts to anchor on are the founding around 2014 to 2015 out of the earlier Cloudius Systems entity, the Palo Alto and Tel Aviv dual headquarters structure, the three-tier pricing model spanning free open source, self-managed Enterprise, and managed Cloud, and the DynamoDB and Cassandra compatibility that differentiates it from most other NoSQL databases in its category.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '19274a99-a56f-41a7-8809-d973ed36645b';

