-- ── SeaTable ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Collaborative no-code database and spreadsheet hybrid platform for building custom tables, workflows, and automations, hosted on servers in Germany.$q$, short_description),
  pricing_model = COALESCE($q$Freemium SaaS with per-user paid tiers, plus on-premises server licenses$q$, pricing_model),
  starting_price = COALESCE($q$Free for up to 25 users; Plus plan from 7 euros per user per month, billed annually$q$, starting_price),
  founded_year = COALESCE(2020, founded_year),
  company_size = COALESCE($q$Small team, part of a joint venture between Seafile Ltd. and SeaTable GmbH$q$, company_size),
  headquarters = COALESCE($q$Mainz, Germany (SeaTable GmbH), in a joint venture with Seafile Ltd. of Guangzhou, China$q$, headquarters),
  languages = ARRAY[$q$German$q$, $q$English$q$, $q$Chinese$q$]::text[],
  seo_title = COALESCE($q$SeaTable Review 2026: Pricing, Features and No-Code Database Guide$q$, seo_title),
  seo_meta_description = COALESCE($q$SeaTable is a no-code spreadsheet-database hybrid hosted in Germany. See 2026 pricing for Free, Plus, and Enterprise plans, plus key features and use cases.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$SeaTable is a collaborative, no-code database and spreadsheet hybrid platform founded in 2020 as a joint venture between Seafile Ltd., a software company based in Guangzhou, China, and SeaTable GmbH, headquartered in Mainz, Germany. The company was founded by Dr. Ralf Dyllick-Brenzinger and Christoph Dyllick-Brenzinger, and its German entity emphasizes data protection by storing SeaTable Cloud data exclusively in German data centers that are monitored and regularly backed up, which the company markets as a differentiator for European customers with strict data residency or GDPR requirements. The product functions similarly to other no-code spreadsheet-database tools in its category, letting users build custom tables, views, forms, and automations without traditional coding, and it supports scripting extensions through Python for more advanced customization. SeaTable offers both a cloud-hosted SaaS product and on-premises server licenses for organizations that want to self-host. The cloud pricing structure has three main published tiers plus a custom Dedicated Cloud option. The Free plan supports up to 25 users at no cost, with limits of 10,000 rows, 2 gigabytes of storage, one month of snapshot history, 100 Python script runs, 3,000 API calls, and 12.5 AI credits, alongside unlimited bases and tables within those row and storage limits. The Plus plan supports unlimited users at 7 euros per user per month when billed annually, or 9 euros per user per month billed monthly, and raises limits to 50,000 rows, 50 gigabytes of storage, six months of snapshot history, 250 Python script runs per user, 10,000 API calls per user, and 50 AI credits. The Enterprise plan costs 14 euros per user per month billed annually, or 18 euros per user per month billed monthly, and includes unlimited rows, 100 gigabytes of storage, 12 months of snapshot history, 1,000 Python script runs per user, 50,000 API calls per user, 500 AI credits, advanced customization options, and SAML single sign-on. A Dedicated Cloud plan requires a minimum of 100 users and offers unlimited rows, 1,000 gigabytes of storage, 24 months of snapshot history, and unlimited Python runs, API calls, and automations, with custom pricing available on request. On-premises SeaTable Server licenses are also available for organizations of 3, 10, 25, or 50-plus users on 1, 2, or 3-year terms, with discounts for longer commitments. SeaTable is commonly compared to other no-code database platforms such as Airtable and Baserow, with its Germany-based data hosting and GDPR-oriented positioning cited most often as its key differentiator for European buyers.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '0909fefb-ee91-4a8f-972b-d6cce78f8b1e';

