-- ── Seatsurfing ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Open-source desk, room, and workspace booking software for hybrid offices, available as a free self-hosted deployment or a hosted SaaS with paid Professional and Enterprise tiers.$q$, short_description),
  pricing_model = COALESCE($q$Open source (free self-hosted) with a freemium hosted SaaS offering paid per-user tiers$q$, pricing_model),
  starting_price = COALESCE($q$Free (self-hosted, or hosted SaaS for up to 10 users); Professional from 0.90 euros per user per month$q$, starting_price),
  founded_year = COALESCE(NULL, founded_year),
  company_size = COALESCE($q$Small team (Seatsurfing GmbH, Friedrichsdorf, Germany)$q$, company_size),
  headquarters = COALESCE($q$Friedrichsdorf, Germany (Seatsurfing GmbH)$q$, headquarters),
  languages = ARRAY[$q$German$q$, $q$English$q$]::text[],
  seo_title = COALESCE($q$Seatsurfing Review 2026: Pricing, Features and Desk Booking Guide$q$, seo_title),
  seo_meta_description = COALESCE($q$Seatsurfing is open-source desk and room booking software for hybrid offices. See 2026 pricing for self-hosted, Free, Professional and Enterprise tiers.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Seatsurfing is open-source desk sharing, room reservation, and hybrid workplace booking software developed by Seatsurfing GmbH, a German company based in Friedrichsdorf, managed by Jan Jonas and Heinrich Beck. The software is published as open source on GitHub under the seatsurfing organization and is designed to let organizations manage flexible workspaces, hot desking, meeting room reservations, and free seating arrangements through a modern web interface with visual floor plan support. Because the core product is open source, organizations can self-host Seatsurfing on their own infrastructure entirely free of charge, with unlimited users and access to all core features, which distinguishes it from many commercial desk-booking SaaS competitors that charge per seat regardless of deployment size. Alongside the self-hosted option, Seatsurfing GmbH also operates a fully managed, cloud-hosted SaaS version with tiered pricing. The hosted Free plan supports up to 10 users at no cost and includes most of Seatsurfing's features, such as Microsoft Teams integration, Microsoft Exchange synchronization, Atlassian Confluence integration, and managed cloud hosting located in Germany, without requiring a credit card to start. The Professional plan removes the user cap and is priced at 0.90 euros per user per month, adding booking approvals and restrictions, recurring bookings, support for custom domains, third-party identity provider integration, a kiosk mode for on-site check-in displays, and 24/7 support; prospective customers can trial the Professional plan free for 30 days without commitment. An Enterprise plan is available for organizations with a minimum of 500 users and offers dedicated infrastructure hosted in either Germany or Finland, maximum data protection guarantees, and 24/7 priority support, with pricing negotiated individually. The self-hosted deployment option also has optional paid support available for organizations that want commercial assistance while still running the open-source software on their own servers. Seatsurfing integrates with workplace collaboration tools including Microsoft Teams, Microsoft Exchange, and Atlassian Confluence, positioning it as a workplace management platform for hybrid offices that need to coordinate desk sharing, room bookings, and shared space allocation as employees split time between office and remote work. Precise founding year and detailed company size information for Seatsurfing GmbH are not consistently published in public sources, so those data points should be treated as unconfirmed rather than stated as fact.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '0e9b4d40-09bf-428c-bae2-5b8bc5c02646';

