-- ── Security Onion ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Free, open-source Linux distribution for threat hunting, enterprise security monitoring, and log management, bundling tools like Suricata, Zeek, and the Elastic Stack.$q$, short_description),
  pricing_model = COALESCE($q$Free and open source software, with paid training, support, and professional services sold separately$q$, pricing_model),
  starting_price = COALESCE($q$Free (open-source distribution); paid training and support plans available on request$q$, starting_price),
  founded_year = COALESCE(2008, founded_year),
  company_size = COALESCE($q$Small company (Security Onion Solutions, LLC, founded 2014)$q$, company_size),
  headquarters = COALESCE($q$Evans, Georgia, USA$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Security Onion Review 2026: Free Threat Hunting Platform Guide$q$, seo_title),
  seo_meta_description = COALESCE($q$Security Onion is a free, open-source Linux distro for threat hunting and security monitoring. See features, bundled tools, and paid training and support options.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Security Onion is a free and open-source Linux distribution built for threat hunting, enterprise security monitoring, and log management, originally started as a personal open-source project by Doug Burks in 2008. As the platform grew in popularity, Burks founded Security Onion Solutions, LLC in 2014 to provide official training, support, and professional services around the free software; the company is headquartered at 717 Bishops Circle in Evans, Georgia, USA. Security Onion itself remains completely free and open source, with the source code publicly available, and it is created and maintained by a community of cybersecurity professionals who use it in their own environments. The distribution bundles a curated set of best-of-breed open-source security tools rather than building everything from scratch, including the Suricata intrusion detection and prevention engine, the Zeek network security monitoring framework, and the Elastic Stack for log storage, search, and visualization, alongside its own analyst-facing interfaces for alert triage and case management. Reported adoption figures cited by the project put downloads at over 1,000,000, with installations reported in nearly every country in the world, reflecting broad usage among security operations centers, government agencies, and individual practitioners worldwide. Because Security Onion is free, the company's revenue model is built entirely around optional paid services layered on top of the free distribution: Security Onion Solutions, LLC positions itself as the only official training and support provider for the platform, offering both on-demand training, available in free and premium tiers, and instructor-led training delivered either in person or in virtual lab environments, plus professional support services covering architecture and hardware planning through step-by-step remote deployment assistance at any deployment scale. None of Security Onion Solutions' pricing for training, support, or professional services is published publicly on its website; the site contains no pricing pages, rate cards, or cost estimates, which is typical of custom, quote-based B2B service pricing that varies according to deployment scale, chosen support tier, and specific customer requirements. The company also offers government pricing through a partner, IntelliGenesis, and lists itself as a seller on AWS Marketplace. For an SEO directory context, the most load-bearing, verifiable facts are that the underlying software is entirely free and open source, that the company behind official commercial services, Security Onion Solutions LLC, was founded in 2014 (five years after the software project itself began in 2008) and is headquartered in Evans, Georgia, and that its bundled toolset centers on Suricata, Zeek, and the Elastic Stack.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '1e225ae3-f536-4753-a9dd-77c8187545ca';

